/** Devolve as microcompetências adequadas para uma ficha técnica.
 *  Combina família1 + família2 (se existir) + etiquetas.
 *  Se nenhuma família está definida, cai para filtro por UC. */
export function microsPorFamilia(
  familia1: string | undefined,
  familia2?: string,
  etiquetas?: string[],
  ucId?: string
): MicroCompetencia[] {
  if (!familia1 && !familia2) {
    // fallback: filtro por UC
    return ucId ? microsPorUC(ucId) : [];
  }

  const ids = new Set<string>();

  // Família principal
  if (familia1 && MICROS_POR_FAMILIA[familia1]) {
    MICROS_POR_FAMILIA[familia1].forEach(id => ids.add(id));
  }

  // Família secundária (peso equivalente)
  if (familia2 && MICROS_POR_FAMILIA[familia2]) {
    MICROS_POR_FAMILIA[familia2].forEach(id => ids.add(id));
  }

  // Etiquetas — adicionam microcompetências específicas
  if (etiquetas && etiquetas.length > 0) {
    etiquetas.forEach(etiqueta => {
      const microsEtiqueta = MICROS_POR_ETIQUETA[etiqueta];
      if (microsEtiqueta) microsEtiqueta.forEach(id => ids.add(id));
    });
  }

  // Sempre incluir as obrigatórias
  ids.add('OBR_01');
  ids.add('OBR_02');
  ids.add('S001');
  ids.add('S002');

  return MICROCOMPETENCIAS.filter(m => ids.has(m.id));
}

export function microsPorUC(uc: string): MicroCompetencia[] {
  const micros = MICROCOMPETENCIAS.filter(m => m.ucPrincipal === uc || m.ucsRelacionadas.includes(uc));
  // Adicionar subtécnicas desta UC que não têm microcompetência equivalente
  try {
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    const { SUBTECNICAS } = require('./subtecnicas');
    const IDS_MICRO_JA_PRESENTES = new Set(micros.map((m: MicroCompetencia) => m.id));
    // IDs de subtécnicas que são equivalentes a microcompetências existentes
    // (para não duplicar na UI)
    const IDS_EQUIV_MICRO = new Set([
      'S050','S051','S056','S054','S090','S093','S092','S095',
      'S097','S099','S100','S101','S102','S107',
      'S030','S031','S032','S034','S035','S033',
      'S040','S041','S042','S043','S103','S098',
      'S164','S164B','S165','S166','S160','S161','S163',
      'S075','S074','S070','S071','S072','S082','S081',
    ]);
    const subsDaUC: MicroCompetencia[] = SUBTECNICAS
      .filter((s: { id: string; uc?: string[] }) =>
        (s.uc || []).includes(uc) && !IDS_EQUIV_MICRO.has(s.id)
      )
      .map((s: { id: string; nome: string; uc?: string[]; criterios?: { criterio: string; como?: string }[] }) => ({
        id: s.id,
        nome: s.nome,
        ucPrincipal: uc,
        ucNome: '',
        ucsRelacionadas: (s.uc || []).filter((u: string) => u !== uc),
        categoria: 'Técnica',
        prioridade: 'B' as const,
        criterios: s.criterios || [],
        nUCs: (s.uc || []).length,
      }));
    // Juntar: micros clássicas + subtécnicas únicas, sem duplicar
    return [...micros, ...subsDaUC.filter(s => !IDS_MICRO_JA_PRESENTES.has(s.id))];
  } catch {
    return micros;
  }
}

export function aptidoesPorUC(uc: string): AptidaoUC[] {
  return APTIDOES_POR_UC[uc] || [];
}

// Calcula media ponderada com pesos temporais (do Excel)
export function mediaTemporalPonderada(avaliacoes: { nota: number; data: string }[]): number {
  if (avaliacoes.length === 0) return 0;
  const agora = new Date();
  let somaPonderada = 0;
  let somaPesos = 0;
  for (const a of avaliacoes) {
    const dataAv = new Date(a.data);
    const diasDif = (agora.getTime() - dataAv.getTime()) / (1000 * 60 * 60 * 24);
    let peso: number;
    if (diasDif <= 90) peso = PARAMETROS_AVALIACAO.pesosTempo.ate3meses;
    else if (diasDif <= 180) peso = PARAMETROS_AVALIACAO.pesosTempo.ate6meses;
    else if (diasDif <= 365) peso = PARAMETROS_AVALIACAO.pesosTempo.ate12meses;
    else peso = PARAMETROS_AVALIACAO.pesosTempo.mais12meses;
    somaPonderada += a.nota * peso;
    somaPesos += peso;
  }
  return somaPesos > 0 ? somaPonderada / somaPesos : 0;
}

export function jaTeveSucesso(avaliacoes: { nota: number; data: string }[]): boolean {
  return avaliacoes.filter(a => a.nota >= PARAMETROS_AVALIACAO.notaMinimaSucesso).length >= PARAMETROS_AVALIACAO.nSucessosConsolidada;
}

export function estaEmRegressao(avaliacoes: { nota: number; data: string }[]): boolean {
  if (avaliacoes.length < 2) return false;
  const ordenadas = [...avaliacoes].sort((a, b) => a.data.localeCompare(b.data));
  const ult = ordenadas[ordenadas.length - 1].nota;
  const pen = ordenadas[ordenadas.length - 2].nota;
  return (ult - pen) <= PARAMETROS_AVALIACAO.regressaoRelevante;
}

export function semEvolucaoSignificativa(avaliacoes: { nota: number; data: string }[]): boolean {
  if (avaliacoes.length < 2) return false;
  const ordenadas = [...avaliacoes].sort((a, b) => a.data.localeCompare(b.data));
  const ult = ordenadas[ordenadas.length - 1].nota;
  const pen = ordenadas[ordenadas.length - 2].nota;
  const diff = ult - pen;
  return diff >= 0 && diff < PARAMETROS_AVALIACAO.diferencaMinSignificativa && ult < PARAMETROS_AVALIACAO.notaMinimaSucesso;
}

// Calcular pontuação de prioridade (do Excel, Prioridade_Avaliacao_v4)
export function calcularPontuacaoPrioridade(
  avaliacoes: { nota: number; data: string }[],
  exigidaPelaFicha: boolean,
  escolhidaPeloAluno: boolean,
  eObrigatoria: boolean
): number {
  if (eObrigatoria) return PARAMETROS_AVALIACAO.pontuacaoPrioridade.obrigatoria;
  if (avaliacoes.length === 0) return PARAMETROS_AVALIACAO.pontuacaoPrioridade.nuncaAvaliada;
  if (estaEmRegressao(avaliacoes)) return PARAMETROS_AVALIACAO.pontuacaoPrioridade.regressao;
  if (semEvolucaoSignificativa(avaliacoes)) return PARAMETROS_AVALIACAO.pontuacaoPrioridade.semEvolucao;
  if (exigidaPelaFicha) return PARAMETROS_AVALIACAO.pontuacaoPrioridade.exigidaPelaFicha;
  if (escolhidaPeloAluno) return PARAMETROS_AVALIACAO.pontuacaoPrioridade.escolhaAluno;
  if (jaTeveSucesso(avaliacoes)) return PARAMETROS_AVALIACAO.pontuacaoPrioridade.consolidada;
  const media = mediaTemporalPonderada(avaliacoes);
  return media > 0 ? PARAMETROS_AVALIACAO.pontuacaoPrioridade.emEvolucao : PARAMETROS_AVALIACAO.pontuacaoPrioridade.nuncaAvaliada;
}
